/*!
 * AdminLTE 3 - Core JS (Simplified)
 * Requires: jQuery
 * Plugins: Treeview, PushMenu
 */
(function ($) {
  'use strict';

  /* ===================== Treeview Plugin =====================
   * Handles expand/collapse of nav-treeview submenus.
   * Usage: $('.has-treeview').Treeview()
   */
  var Treeview = function (element, options) {
    this.element = element;
    this.options = $.extend({}, Treeview.DEFAULTS, options);
    this.init();
  };

  Treeview.DEFAULTS = {
    trigger: '.nav-item > .nav-link',
    submenu: '.nav-treeview',
    openClass: 'menu-open',
    animationSpeed: 200
  };

  Treeview.prototype.init = function () {
    var self = this;
    var $element = $(this.element);
    var $trigger = $element.find(this.options.trigger);

    $trigger.on('click', function (e) {
      var $parent = $(this).parent('.nav-item');
      var $submenu = $parent.children(self.options.submenu);
      if (!$submenu.length) return; // no submenu, allow normal navigation
      e.preventDefault();

      var isOpening = !$parent.hasClass(self.options.openClass);

      // Close other open siblings
      $parent.siblings('.' + self.options.openClass).each(function () {
        var $sibling = $(this);
        $sibling.removeClass(self.options.openClass);
        $sibling.children(self.options.submenu).stop(true).slideUp(self.options.animationSpeed);
      });

      if (isOpening) {
        $parent.addClass(self.options.openClass);
        $submenu.stop(true).slideDown(self.options.animationSpeed);
      } else {
        $parent.removeClass(self.options.openClass);
        $submenu.stop(true).slideUp(self.options.animationSpeed);
      }
    });
  };

  // jQuery plugin definition
  function Plugin(option) {
    return this.each(function () {
      var $this = $(this);
      var data = $this.data('lte.treeview');
      var options = typeof option === 'object' ? option : {};
      if (!data) {
        $this.data('lte.treeview', (data = new Treeview(this, options)));
      }
    });
  }

  $.fn.Treeview = Plugin;


  /* ===================== PushMenu Plugin =====================
   * Handles sidebar toggle on mobile and sidebar-mini collapse on desktop.
   * Usage: $('.nav-sidebar').PushMenu({ toggleButtonSelector: '.nav-link' })
   */
  var PushMenu = function (element, options) {
    this.element = element;
    this.options = $.extend({}, PushMenu.DEFAULTS, options);
    this.init();
  };

  PushMenu.DEFAULTS = {
    sidebarCollapseClass: 'sidebar-collapse',
    sidebarMiniClass: 'sidebar-mini',
    sidebarOpenClass: 'sidebar-open',
    overlayClass: 'sidebar-overlay',
    toggleButtonSelector: '[data-widget="pushmenu"]',
    autoCollapseSize: 992,
    animationSpeed: 200
  };

  PushMenu.prototype.init = function () {
    var self = this;
    var $body = $('body');
    var $sidebar = $(this.element);

    // Toggle button handler
    $(self.options.toggleButtonSelector).on('click', function (e) {
      e.preventDefault();
      self.toggle();
    });

    // Auto-collapse on resize
    $(window).on('resize', function () {
      self.autoCollapse();
    });

    // Close sidebar when clicking overlay (mobile)
    $body.on('click', '.' + self.options.overlayClass, function () {
      self.close();
    });

    // Initial state
    self.autoCollapse();
  };

  PushMenu.prototype.toggle = function () {
    var $body = $('body');
    var windowWidth = $(window).width();

    if (windowWidth < this.options.autoCollapseSize) {
      // Mobile: toggle sidebar open/close with overlay
      var $sidebar = $(this.element);
      var $overlay = $('.' + this.options.overlayClass);

      if ($sidebar.hasClass(this.options.sidebarOpenClass)) {
        this.close();
      } else {
        this.open();
      }
    } else {
      // Desktop: toggle sidebar-collapse
      $body.toggleClass(this.options.sidebarCollapseClass);
    }
  };

  PushMenu.prototype.open = function () {
    var $sidebar = $(this.element);
    var $overlay = $('.' + this.options.overlayClass);

    if ($overlay.length === 0) {
      $overlay = $('<div class="' + this.options.overlayClass + '"></div>');
      $('body').append($overlay);
    }

    $sidebar.addClass(this.options.sidebarOpenClass);
    $overlay.addClass('active');
  };

  PushMenu.prototype.close = function () {
    var $sidebar = $(this.element);
    var $overlay = $('.' + this.options.overlayClass);

    $sidebar.removeClass(this.options.sidebarOpenClass);
    $overlay.removeClass('active');
  };

  PushMenu.prototype.autoCollapse = function () {
    var $body = $('body');
    var windowWidth = $(window).width();

    if (windowWidth < this.options.autoCollapseSize) {
      // On mobile: close sidebar
      this.close();
    }
  };

  // jQuery plugin definition
  function PluginPushMenu(option) {
    return this.each(function () {
      var $this = $(this);
      var data = $this.data('lte.pushmenu');
      var options = typeof option === 'object' ? option : {};
      if (!data) {
        $this.data('lte.pushmenu', (data = new PushMenu(this, options)));
      }
    });
  }

  $.fn.PushMenu = PluginPushMenu;


  /* ===================== Auto Init on DOM Ready ===================== */
  $(function () {
    // Initialize Treeview for sidebar
    if ($('.nav-sidebar').length) {
      $('.nav-sidebar').Treeview();
    }

    // Initialize PushMenu on main-sidebar
    if ($('.main-sidebar').length) {
      $('.main-sidebar').PushMenu();
    }

    // Header dropdown toggle
    $('[data-bs-toggle="dropdown"]').on('click', function (e) {
      e.preventDefault();
      e.stopPropagation();
      var $menu = $(this).next('.dropdown-menu');
      $('.dropdown-menu').not($menu).removeClass('show');
      $menu.toggleClass('show');
    });
    $(document).on('click', function () {
      $('.main-header .dropdown-menu').removeClass('show');
    });
  });

})(jQuery);
